import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  BarChart,
  Bar,
  Cell,
  PieChart,
  Pie,
  Legend,
} from 'recharts';
import api from '../api';
import './StudentDashboard.css';

const PRIMARY = '#10b981';
const SKILL_COLORS = {
  'Memory Skills': '#10b981',
  'Attention & Focus': '#06b6d4',
  'Logical Reasoning': '#34d399',
  'Problem Solving': '#f59e0b',
  'Verbal Ability': '#ec4899',
  'Numerical Ability': '#6366f1',
  'Analytical Thinking': '#0ea5e9',
  'Critical Thinking': '#ef4444',
  'Decision Making': '#84cc16',
  'Pattern Recognition': '#f97316',
};

const TrendTooltip = ({ active, payload }) => {
  if (active && payload && payload.length) {
    const data = payload[0].payload;
    return (
      <div className="trend-tooltip">
        <p className="tooltip-date">{data.date}</p>
        <div className="tooltip-content">
          <p className="tooltip-subject">{data.subject}</p>
          <p className="tooltip-score">Score : {data.percentage}%</p>
        </div>
      </div>
    );
  }
  return null;
};

const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent, index }) => {
  const RADIAN = Math.PI / 180;
  const radius = outerRadius * 1.2;
  const x = cx + radius * Math.cos(-midAngle * RADIAN);
  const y = cy + radius * Math.sin(-midAngle * RADIAN);

  return (
    <text
      x={x}
      y={y}
      fill={Object.values(SKILL_COLORS)[index % 10]}
      textAnchor={x > cx ? 'start' : 'end'}
      dominantBaseline="central"
      fontSize="12"
      fontWeight="700"
    >
      {`${(percent * 100).toFixed(0)}%`}
    </text>
  );
};

export default function StudentDashboard() {
  const { user } = useAuth();
  const [stats, setStats] = useState(null);
  const [assessments, setAssessments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [uploading, setUploading] = useState(false);
  const [selectedResult, setSelectedResult] = useState(null);
  const [activeUploadId, setActiveUploadId] = useState(null);
  const fileInputRef = useRef(null);

  useEffect(() => {
    Promise.all([
      api.get('/results/dashboard-stats'),
      api.get('/assessments'),
    ])
      .then(([statsRes, assessRes]) => {
        setStats(statsRes.data);
        setAssessments(assessRes.data.slice(0, 5));
      })
      .catch(() => setStats({ skillSummary: {}, trendData: [], recentResults: [] }))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="dashboard-loading">Loading dashboard...</div>;

  const trendData = stats?.trendData || [];
  const recentResults = stats?.recentResults || [];

  // Pie chart data: results count, average score, and share percentage per subject
  const totalResults = recentResults.length;
  const subjectDistribution = totalResults ? Object.entries(
    recentResults.reduce((acc, r) => {
      const name = r.subject?.name || 'Unknown';
      if (!acc[name]) {
        acc[name] = { count: 0, totalScore: 0 };
      }
      acc[name].count += 1;
      acc[name].totalScore += r.percentage;
      return acc;
    }, {})
  ).map(([name, data]) => ({
    name,
    value: data.count,
    avgScore: Math.round(data.totalScore / data.count),
    sharePercentage: Math.round((data.count / totalResults) * 100)
  })) : [];

  const avgScore = recentResults.length
    ? Math.round(recentResults.reduce((acc, r) => acc + r.percentage, 0) / recentResults.length)
    : 0;

  const upcoming = assessments[0];

  const handleUpload = (e, result) => {
    e.stopPropagation();
    setActiveUploadId(result._id);
    fileInputRef.current.click();
  };

  const handleFileChange = async (e) => {
    const file = e.target.files[0];
    if (!file || !activeUploadId) return;

    const formData = new FormData();
    formData.append('assignment', file);

    setUploading(true);
    try {
      const res = await api.post(`/results/upload-assignment/${activeUploadId}`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      alert('Assignment uploaded successfully!');
      // Refresh results to show new status if needed
      const statsRes = await api.get('/results/dashboard-stats');
      setStats(statsRes.data);
    } catch (err) {
      console.error(err);
      const msg = err.response?.data?.message || 'Failed to upload assignment.';
      alert(msg);
    } finally {
      setUploading(false);
      setActiveUploadId(null);
      e.target.value = null; // Clear input
    }
  };

  return (
    <div className="student-dashboard">
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileChange}
        style={{ display: 'none' }}
      />
      <header className="welcome-header">
        <h1 className="dashboard-title">Welcome back, {user?.name || 'User'}</h1>
        <p className="dashboard-subtitle">Here's your Cognitive Assessment performance overview.</p>
      </header>

      <div className="stats-grid">
        <div className="stat-card color-1">
          <div className="stat-header">
            <div className="stat-icon-box">📊</div>
          </div>
          <div className="stat-value">
            {recentResults.length
              ? Math.round(recentResults.reduce((acc, r) => acc + r.percentage, 0) / recentResults.length)
              : 0}%
          </div>
          <span className="stat-label">Average Score</span>
          <div className="stat-trend trend-up">
            ↑ 4.2% from last month
          </div>
        </div>
        <div className="stat-card color-2">
          <div className="stat-header">
            <div className="stat-icon-box">✅</div>
          </div>
          <div className="stat-value">{recentResults.length}</div>
          <span className="stat-label">Tests Completed</span>
          <div className="stat-trend">
            Steady progress
          </div>
        </div>
        <div className="stat-card color-3">
          <div className="stat-header">
            <div className="stat-icon-box">🏆</div>
          </div>
          <div className="stat-value" style={{ fontSize: '1.5rem', paddingTop: '10px' }}>
            {subjectDistribution.length ? subjectDistribution.sort((a, b) => b.value - a.value)[0].name : 'N/A'}
          </div>
          <span className="stat-label">Main Skill</span>
        </div>
      </div>

      <div className="dashboard-charts">
        <section className="chart-card glass-card">
          <h2>Performance trend</h2>
          <div className="chart-wrap">
            {trendData.length ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={trendData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(255,255,255,0.05)" />
                  <XAxis
                    dataKey="date"
                    axisLine={false}
                    tickLine={false}
                    tick={{ fontSize: 12, fill: '#a1a1aa', fontWeight: 500 }}
                  />
                  <YAxis
                    domain={[0, 100]}
                    axisLine={false}
                    tickLine={false}
                    tick={{ fontSize: 12, fill: '#a1a1aa', fontWeight: 500 }}
                  />
                  <Tooltip content={<TrendTooltip />} />
                  <Bar
                    dataKey="percentage"
                    fill={PRIMARY}
                    radius={[6, 6, 0, 0]}
                    barSize={32}
                  />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="chart-empty">Complete assignments to see your trend.</div>
            )}
          </div>
        </section>


        <section className="chart-card glass-card">
          <h2>Activity Distribution</h2>
          <div className="chart-wrap pie-chart-container">
            {subjectDistribution.length ? (
              <>
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Legend verticalAlign="top" align="center" iconType="circle" wrapperStyle={{ fontSize: '12px', paddingBottom: '20px', color: '#a1a1aa' }} />
                    <Pie
                      data={subjectDistribution}
                      cx="50%"
                      cy="50%"
                      outerRadius={80}
                      dataKey="value"
                      label={renderCustomizedLabel}
                      labelLine={{ stroke: 'rgba(255,255,255,0.1)', strokeWidth: 1 }}
                    >
                      {subjectDistribution.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={Object.values(SKILL_COLORS)[index % 10]} />
                      ))}
                    </Pie>
                    <Tooltip
                      contentStyle={{ borderRadius: '12px', border: '1px solid rgba(255,255,255,0.1)', background: '#1a1a1a', color: '#fff' }}
                      itemStyle={{ color: '#fff' }}
                    />
                  </PieChart>
                </ResponsiveContainer>
              </>
            ) : (
              <div className="chart-empty">No activities to show.</div>
            )}
          </div>
        </section>
      </div>

      <section className="recent-results glass-card">
        <h2>Recent Performance</h2>
        {recentResults.length ? (
          <>
            <div className="results-table-header">
              <span>Subject</span>
              <span className="col-score">Score</span>
              <span className="col-date">Date</span>
              <span className="col-action">Assignment</span>
            </div>
            <ul className="results-list">
              {recentResults.map((r) => (
                <li key={r._id} className="result-item" onClick={() => setSelectedResult(r)} style={{ cursor: 'pointer' }}>
                  <span className="result-subject">
                    <span style={{ width: 8, height: 8, borderRadius: '50%', background: PRIMARY, boxShadow: `0 0 10px ${PRIMARY}` }}></span>
                    <span className="subject-link">{r.subject?.name}</span>
                  </span>
                  <span className="result-score col-score">{r.percentage}%</span>
                  <span className="result-date col-date">{new Date(r.completedAt).toLocaleDateString()}</span>
                  <span className="result-action col-action">
                    {r.assignmentFile ? (
                      <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                        <a
                          href={`/uploads/${r.assignmentFile}`}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="badge-link"
                          title="View Assignment"
                          onClick={(e) => e.stopPropagation()}
                        >
                          <span className="status-badge success">Uploaded</span>
                          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ width: 16, height: 16 }}>
                            <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path>
                            <circle cx="12" cy="12" r="3"></circle>
                          </svg>
                        </a>
                        <button
                          className={`upload-btn-mini ${uploading && activeUploadId === r._id ? 'uploading' : ''}`}
                          onClick={(e) => handleUpload(e, r)}
                          disabled={uploading}
                          title="Replace Assignment"
                        >
                          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ width: 16, height: 16 }}>
                            <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path>
                            <polyline points="17 8 12 3 7 8"></polyline>
                            <line x1="12" y1="3" x2="12" y2="15"></line>
                          </svg>
                        </button>
                      </div>
                    ) : (
                      <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                        <span className="status-badge">No File</span>
                        <button
                          className={`upload-btn-mini ${uploading && activeUploadId === r._id ? 'uploading' : ''}`}
                          onClick={(e) => handleUpload(e, r)}
                          disabled={uploading}
                          title="Upload Assignment"
                        >
                          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ width: 16, height: 16 }}>
                            <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path>
                            <polyline points="17 8 12 3 7 8"></polyline>
                            <line x1="12" y1="3" x2="12" y2="15"></line>
                          </svg>
                        </button>
                      </div>
                    )}
                  </span>
                </li>
              ))}
            </ul>
          </>
        ) : (
          <p className="no-data">No results yet. Take an assignment to see your scores here.</p>
        )}
      </section>

      {
        selectedResult && (
          <div className="modal-overlay" onClick={() => setSelectedResult(null)}>
            <div className="modal glass-card" onClick={e => e.stopPropagation()}>
              <div className="modal-header">
                <h3>Assignment Result</h3>
                <button className="btn-close" onClick={() => setSelectedResult(null)}>✕</button>
              </div>
              <div className="modal-body">
                <div className="result-summary">
                  <div className="summary-item">
                    <label>Subject</label>
                    <span>{selectedResult.subject?.name}</span>
                  </div>
                  <div className="summary-item">
                    <label>Assignment</label>
                    <span>{selectedResult.assessment?.title}</span>
                  </div>
                  <div className="summary-item">
                    <label>Score</label>
                    <span className="score-high">{selectedResult.percentage}%</span>
                  </div>
                  <div className="summary-item">
                    <label>Completed On</label>
                    <span>{new Date(selectedResult.completedAt).toLocaleString()}</span>
                  </div>
                </div>

                <div className="result-details">
                  <h4>Performance Breakdown</h4>
                  <p>You answered <strong>{selectedResult.score}</strong> correct out of <strong>{selectedResult.totalQuestions}</strong> questions.</p>
                  <div className="progress-bar-wrap">
                    <div className="progress-bar-fill" style={{ width: `${selectedResult.percentage}%` }}></div>
                  </div>
                </div>
              </div>
              <div className="modal-footer">
                <button className="btn btn-primary" onClick={() => setSelectedResult(null)}>Close</button>
              </div>
            </div>
          </div>
        )
      }
    </div >
  );
}
